import json, os, re

def load_var(v):
    if isinstance(v, str) and os.path.exists(v):
        with open(v, 'r', encoding='utf-8', errors='replace') as f:
            return json.load(f)
    return v

contents = load_var(var_call_cYwq5Lsx3wtApssHMdw58vow)

copyright_pat = re.compile(r'copyright|\u00a9|\(c\)|©', flags=re.IGNORECASE)

repo_readmes = {}
for r in contents:
    repo = r.get('sample_repo_name')
    path = r.get('sample_path','')
    content = r.get('content')
    if not repo or not path or not path.lower().endswith('readme.md'):
        continue
    if content is None or not isinstance(content, str):
        continue
    s = content.strip()
    if s == '' or s.lower() == 'none':
        continue
    if '\x00' in s:
        continue
    repo_readmes.setdefault(repo, []).append(s)

count_repos = len(repo_readmes)
count_with_copyright = 0
repos_with_copyright = []
for repo, texts in repo_readmes.items():
    if any(copyright_pat.search(t) for t in texts):
        count_with_copyright += 1
        repos_with_copyright.append(repo)

result = {
    'repos_checked': count_repos,
    'repos_with_copyright_in_readme_md': count_with_copyright,
    'proportion': None if count_repos==0 else count_with_copyright/count_repos,
    'percentage': None if count_repos==0 else (count_with_copyright/count_repos)*100,
    'repos_with_copyright_list': repos_with_copyright
}

print('__RESULT__:')
print(json.dumps(result))

